def parse_monto(raw: str):
    t = raw.strip()
    if t == "":
        return (False, None, "vacío")
    try:
        n = int(t)
    except ValueError:
        return (False, None, "no entero")
    if n < 0:
        return (False, None, "negativo")
    return (True, n, None)

for v in ["10", "-1", "x", ""]:
    print(v, parse_monto(v))
